@app.route('/sso/login')
def sso_login():
    auth = OneLogin_Saml2_Auth(prepare_flask_request(request), custom_base_path='path_to_your_saml_config/')
    return redirect(auth.login())

@app.route('/sso/acs', methods=['POST'])
def sso_acs():
    auth = OneLogin_Saml2_Auth(prepare_flask_request(request), custom_base_path='path_to_your_saml_config/')
    auth.process_response()
    
    errors = auth.get_errors()
    if errors:
        return f"Error: {', '.join(errors)}", 400
    
    if not auth.is_authenticated():
        return "User not authenticated", 403
    
    response_xml = request.form['SAMLResponse']
    root = ET.fromstring(response_xml)
    
    # Validate signature exists (simple check)
    signature = root.find('.//{http://www.w3.org/2000/09/xmldsig#}Signature')
    if signature is None:
        return "Signature missing", 400
    
    # Extract assertions
    assertions = root.findall('.//{urn:oasis:names:tc:SAML:2.0:assertion}Assertion')
    for assertion in assertions:
        subject = assertion.find('.//{urn:oasis:names:tc:SAML:2.0:assertion}Subject')
        if subject is not None:
            name_id = subject.find('.//{urn:oasis:names:tc:SAML:2.0:assertion}NameID')
            if name_id is not None:
                session['user'] = name_id.text

    return redirect('/dashboard')

@app.route('/dashboard')
def dashboard():
    if 'user' in session:
        return f"Welcome, {session['user']}!"
    return redirect('/sso/login')

